import UIKit

class ItemTableViewCell: UITableViewCell {
    var itemName: String = "" {
        didSet {
            textLabel?.text = itemName
        }
    }
}

class ViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    let items = ["Apple", "Banana", "Orange"]

    @IBOutlet weak var tableView: UITableView!

    override func viewDidLoad() {
        super.viewDidLoad()
        tableView.dataSource = self
        tableView.delegate = self
    }

    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return items.count
    }

    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "ItemCell", for: indexPath)
        cell.itemName = items[indexPath.row]
        return cell
    }
}

// Giải thích:
// 1. Tạo một UITableViewCell tùy chỉnh để hiển thị tên item.
// 2. ViewController conform với UITableViewDataSource và UITableViewDelegate.
// 3. Trong viewDidLoad(), thiết lập dataSource và delegate cho UITableView.
// 4. Implement các hàm required của UITableViewDataSource để cung cấp dữ liệu cho UITableView.
